def solve(grid: Array[Array[Long]], k: Long): Long = {
    if (grid.isEmpty || grid(0).isEmpty) return 0L

    val m = grid.length
    val n = grid(0).length
    val visited = Array.ofDim[Boolean](m, n)
    var count = 0L

    def dfs(i: Int, j: Int): Long = {
        if (i < 0 || i >= m || j < 0 || j >= n || grid(i)(j) == 0 || visited(i)(j)) {
            return 0L
        }
        visited(i)(j) = true
        var total = grid(i)(j)
        total += dfs(i + 1, j)
        total += dfs(i - 1, j)
        total += dfs(i, j + 1)
        total += dfs(i, j - 1)
        total
    }

    for (i <- 0 until m) {
        for (j <- 0 until n) {
            if (grid(i)(j) != 0 && !visited(i)(j)) {
                val total = dfs(i, j)
                if (total % k == 0) {
                    count += 1
                }
            }
        }
    }
    count
}
